import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Swagger","description":"Generate OpenAPI v2 / v3 documents from decorated controllers and serve Swagger UI.","frontmatter":{"title":"Swagger","description":"Generate OpenAPI v2 / v3 documents from decorated controllers and serve Swagger UI.","relatedPlugins":["decorators"]},"headers":[],"relativePath":"swagger/index.md","filePath":"swagger/index.md","lastUpdated":1777908017000}'),s={name:"swagger/index.md"};function n(i,e,l,d,c,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="routup-swagger" tabindex="-1">@routup/swagger <a class="header-anchor" href="#routup-swagger" aria-label="Permalink to &quot;@routup/swagger&quot;">​</a></h1><p>Two things in one plugin:</p><ol><li><strong>Generator</strong> — walk a TypeScript codebase, extract route metadata via <a href="https://github.com/trapi/trapi" target="_blank" rel="noreferrer"><code>@trapi/metadata</code></a>, and emit an OpenAPI v2 or v3 document.</li><li><strong>UI</strong> — mount <a href="https://github.com/swagger-api/swagger-ui" target="_blank" rel="noreferrer">Swagger UI</a> at any path to serve the generated document interactively.</li></ol><p>The package also bundles the <code>@trapi/metadata</code> preset that interprets routup&#39;s <code>@D*</code> decorators (<code>@DController</code>, <code>@DGet</code>, <code>@DBody</code>, …) — no separate preset install needed. Pair with <a href="/decorators/"><code>@routup/decorators</code></a> so controllers and parameter decorators are the source of truth.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @routup/swagger</span></span></code></pre></div><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><ul><li>You want OpenAPI docs that stay in sync with your handlers — the generator reads the same decorators that mount the routes</li><li>You want Swagger UI inline in the same routup app, no separate process</li><li>You&#39;re publishing a public API and need a contract artifact for client codegen</li></ul><p>If you&#39;re hand-writing your OpenAPI document (or generating it from another source), you only need the <strong>UI</strong> half — skip the generator and feed <code>swaggerUI()</code> your existing <code>swagger.json</code> / <code>openapi.yaml</code>.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./generator">Generator</a> — <code>generate()</code>, V2 vs V3, output paths</li><li><a href="./ui">UI</a> — <code>swaggerUI()</code>, mounting, custom UI options</li><li><a href="/decorators/"><code>@routup/decorators</code></a> — write controllers in the shape the generator expects</li></ul>',11)])])}const g=a(s,[["render",n]]);export{u as __pageData,g as default};
